 1	import * as React from 'react';
 2	import { Button, ButtonVariant, Popover, PopoverPosition, TextInput } from '@patternfly/react-core';
 3	import { KialiIcon } from '../../config/KialiIcon';
 4	import { kialiStyle } from 'styles/StyleUtils';
 5	
 6	interface LabelFiltersProps {
 7	  filterAdd: (value: string) => void;
 8	  isActive: (value: string) => boolean;
 9	  onChange: (value: any) => void;
10	  value: string;
11	}
12	
13	const infoIconStyle = kialiStyle({
14	  marginLeft: '0.5rem',
15	  alignSelf: 'center'
16	});
17	
18	export const LabelFilters: React.FC<LabelFiltersProps> = (props: LabelFiltersProps) => {
19	  const onKeyDown = (e: React.KeyboardEvent): void => {
20	    if (e.key === 'Enter') {
21	      if (props.value && props.value.length > 0) {
22	        props.value.split(' ').map(val => !props.isActive(val) && props.filterAdd(val));
23	      }
24	    }
25	  };
26	
27	  return (
28	    <>
29	      <TextInput
30	        id="filter_input_label"
31	        type="text"
32	        value={props.value}
33	        aria-label="Filter Input Label"
34	        placeholder="Set Label"
35	        onChange={(_event, value) => props.onChange(value)}
36	        onKeyDown={e => onKeyDown(e)}
37	        style={{ width: 'auto' }}
38	      />
39	
40	      <Popover
41	        headerContent={<span>Label Filter Help</span>}
42	        position={PopoverPosition.right}
43	        bodyContent={
44	          <>
45	            To set a label filter you must enter values like.
46	            <br />
47	            <ul style={{ listStyleType: 'circle', marginLeft: '1.25rem' }}>
48	              <li>Filter by label presence: label</li>
49	              <li>Filter by label and value: label=value</li>
50	              <li>
51	                Filter by more than one label and one or more values:
52	                <br />
53	                label=value label2=value2,value2-2
54	                <br />
55	                (separate with ' ')
56	              </li>
57	            </ul>
58	          </>
59	        }
60	      >
61	        <Button variant={ButtonVariant.link} className={infoIconStyle} isInline>
62	          <KialiIcon.Help />
63	        </Button>
64	      </Popover>
65	    </>
66	  );
67	};

